// Provide a deterministic normalized content item for manual testing.
return [{
  json: {
    id: 'manual:https://example.com/ai-agent',
    source: 'manual',
    title: 'AI Agent 與工作流',
    url: 'https://example.com/ai-agent',
    language: 'zh-TW',
    content: 'AI Agent 不應只負責生成文字，也應根據工具結果規劃下一步。',
    images: [],
    tags: ['AI', 'n8n'],
    score: 0,
    shouldWrite: false,
    analysis: {},
    metadata: {
      createdAt: new Date().toISOString(),
      collector: 'manual-test',
      version: '1.0.0',
      status: 'normalized'
    }
  }
}];

// Build a strict JSON-only prompt for the analysis model.
const item = $input.first().json;

if (!item.content || !item.url) {
  throw new Error('Normalized content requires url and content');
}

const systemPrompt = `你是 Phoenix AI Content Engine 的內容分析員。你的任務是判斷輸入內容是否值得擴寫成繁體中文 Medium 深度長文。不要直接撰寫文章。只輸出合法 JSON，不要 Markdown code fence。輸出格式：{"topic":"主題","coreIdea":"核心觀點","audience":"目標讀者","score":0,"shouldWrite":false,"angles":["延伸方向"],"keywords":["關鍵詞"],"researchQuestions":["需要查證的問題"],"riskNotes":["事實、版權或引用風險"]}。評分標準：原始觀點與洞察 30、可延伸深度 25、實用性 20、可取得可信來源 15、時效與討論價值 10。shouldWrite 僅在 score >= 70 時為 true。不得捏造原文不存在的事實。`;

const userPrompt = JSON.stringify({
  title: item.title,
  url: item.url,
  source: item.source,
  language: item.language,
  content: item.content
});

return [{
  json: {
    contentItem: item,
    systemPrompt,
    userPrompt
  }
}];

