// Parse the primary response and decide whether fallback is required.
const response = $input.first().json;
const original = $('BuildAnalyzerPrompt').first().json.contentItem;

const statusCode = response.statusCode ?? 0;
const raw = response.body?.choices?.[0]?.message?.content ?? '';
let analysis = null;
let parseError = null;

try {
  analysis = JSON.parse(String(raw).replace(/^```json\s*|\s*```$/g, '').trim());
} catch (error) {
  parseError = error.message;
}

const valid = statusCode >= 200 &&
  statusCode < 300 &&
  analysis &&
  Number.isFinite(Number(analysis.score)) &&
  typeof analysis.shouldWrite === 'boolean';

return [{
  json: {
    original,
    provider: 'openrouter',
    statusCode,
    raw,
    analysis,
    valid,
    fallbackRequired: !valid,
    error: parseError
  }
}];

