// Parse the NVIDIA fallback response.
const response = $input.first().json;
const original = $('BuildAnalyzerPrompt').first().json.contentItem;
const statusCode = response.statusCode ?? 0;
const raw = response.body?.choices?.[0]?.message?.content ?? '';

let analysis;
try {
  analysis = JSON.parse(String(raw).replace(/^```json\s*|\s*```$/g, '').trim());
} catch (error) {
  throw new Error(`NVIDIA response is not valid JSON: ${error.message}`);
}

if (!(statusCode >= 200 && statusCode < 300)) {
  throw new Error(`NVIDIA request failed with status ${statusCode}`);
}

return [{
  json: {
    original,
    provider: 'nvidia',
    analysis
  }
}];

// Merge the selected analysis into the normalized content contract.
const item = $input.first().json;
const original = item.original;
const analysis = item.analysis;

const score = Math.max(0, Math.min(100, Number(analysis.score ?? 0)));
const shouldWrite = score >= 70 && analysis.shouldWrite === true;

return [{
  json: {
    ...original,
    score,
    shouldWrite,
    analysis: {
      topic: String(analysis.topic ?? ''),
      coreIdea: String(analysis.coreIdea ?? ''),
      audience: String(analysis.audience ?? ''),
      angles: Array.isArray(analysis.angles) ? analysis.angles : [],
      keywords: Array.isArray(analysis.keywords) ? analysis.keywords : [],
      researchQuestions: Array.isArray(analysis.researchQuestions) ? analysis.researchQuestions : [],
      riskNotes: Array.isArray(analysis.riskNotes) ? analysis.riskNotes : []
    },
    metadata: {
      ...original.metadata,
      analyzer: '03-analyze-content',
      analyzerVersion: '0.3.0',
      provider: item.provider,
      status: 'analyzed',
      analyzedAt: new Date().toISOString()
    }
  }
}];
